// AsLocalDate returns the union data inside the ClearableDate as a LocalDate
func (t ClearableDate) AsLocalDate() (LocalDate, error) {
	var body LocalDate
	err := json.Unmarshal(t.union, &body)
	return body, err
}

// FromLocalDate overwrites any union data inside the ClearableDate as the provided LocalDate
func (t *ClearableDate) FromLocalDate(v LocalDate) error {
	b, err := json.Marshal(v)
	t.union = b
	return err
}

// MergeLocalDate performs a merge with any union data inside the ClearableDate, using the provided LocalDate
func (t *ClearableDate) MergeLocalDate(v LocalDate) error {
	b, err := json.Marshal(v)
	if err != nil {
		return err
	}

	merged, err := runtime.JSONMerge(t.union, b)
	t.union = merged
	return err
}

